 3	static PyObject* fastmath_fast_sum(PyObject* self, PyObject* args) {
 4	    PyObject* input_list;
 5	    if (!PyArg_ParseTuple(args, "O", &input_list)) {
 6	        return NULL;
 7	    }
 8	
 9	    if (!PyList_Check(input_list)) {
10	        PyErr_SetString(PyExc_TypeError, "Argument must be a list");
11	        return NULL;
12	    }
13	
14	    Py_ssize_t size = PyList_Size(input_list);
15	    double total = 0.0;
16	
17	    for (Py_ssize_t i = 0; i < size; i++) {
18	        PyObject* item = PyList_GetItem(input_list, i);
19	        if (PyLong_Check(item)) {
20	            total += (double)PyLong_AsLong(item);
21	        } else if (PyFloat_Check(item)) {
22	            total += PyFloat_AsDouble(item);
23	        } else {
24	            PyErr_SetString(PyExc_TypeError,
25	                "List items must be int or float");
26	            return NULL;
27	        }
28	    }
29	
30	    return PyFloat_FromDouble(total);
31	}
